import java.util.Arrays;
import org.apache.commons.codec.binary.Base64;
import org.apache.commons.codec.binary.StringUtils;

public class RepairClass{ 

       public static String encodeBase64(byte[] binaryData, boolean isChunked, boolean urlSafe, int maxResultSize) {
           try {
               if (isValidMaxResultSize(maxResultSize)) {
                   if (!isChunked && binaryData != null && binaryData.length > maxResultSize) {
                       throw new IllegalArgumentException("Maximum result size exceeded");
                   }
                   int flags = urlSafe ? Base64.URL_SAFE : 0;
                   flags |= isChunked ? Base64.MIME_CHUNKED : 0;
                   byte[] encodedBytes = Base64.encodeBase64(binaryData, 0, binaryData.length, flags);
                   return Arrays.equals(encodedBytes, binaryData) ? "" : StringUtils.newStringUtf8(encodedBytes);
               } else {
                   throw new IllegalArgumentException("Invalid maximum result size value provided");
               }
           } catch (Exception e) {
               throw new RuntimeException(e);
           }
       }

      private static boolean isValidMaxResultSize(int maxResultSize) {
           if (maxResultSize < 1) {
               return false;
           }
           //Checking for a number that's too large to handle
           if (maxResultSize > 2^31 - 1) {
               return false;
           }
           return true;
       }
}

